"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

type StepperContextValue = {
  activeStep: number
  orientation: "horizontal" | "vertical"
  onStepClick: (step: number) => void
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepperContext() {
  const ctx = React.useContext(StepperContext)
  if (!ctx) {
    throw new Error("Stepper sub-components must be rendered inside <Stepper>.")
  }
  return ctx
}

type StepperItemContextValue = {
  step: number
  status: "active" | "completed" | "pending"
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItemContext() {
  const ctx = React.useContext(StepperItemContext)
  if (!ctx) {
    throw new Error(
      "StepperItem sub-components must be rendered inside <StepperItem>."
    )
  }
  return ctx
}

// ---------------------------------------------------------------------------
// Stepper (root container)
// ---------------------------------------------------------------------------

interface StepperProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "onChange"> {
  /**
   * The controlled active step (1-based). Use together with `onStepChange`.
   */
  step?: number
  /**
   * The initial active step for an uncontrolled stepper.
   * @default 1
   */
  defaultStep?: number
  /** Called when the active step changes (trigger clicked or external nav). */
  onStepChange?: (step: number) => void
  /** Layout direction of the step list.
   * @default "horizontal"
   */
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  step,
  defaultStep = 1,
  onStepChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: StepperProps) {
  const [internalStep, setInternalStep] = React.useState(defaultStep)
  const isControlled = step !== undefined
  const activeStep = isControlled ? step : internalStep

  const handleStepClick = React.useCallback(
    (next: number) => {
      if (!isControlled) setInternalStep(next)
      onStepChange?.(next)
    },
    [isControlled, onStepChange]
  )

  return (
    <StepperContext.Provider
      value={{ activeStep, orientation, onStepClick: handleStepClick }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-row items-start" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperItem
// ---------------------------------------------------------------------------

interface StepperItemProps extends React.HTMLAttributes<HTMLDivElement> {
  /** The step number this item represents (1-based). */
  step: number
  /**
   * Force this step to display as completed regardless of the active step.
   * Useful when you control completion state independently.
   */
  completed?: boolean
}

function StepperItem({
  step,
  completed,
  className,
  children,
  ...props
}: StepperItemProps) {
  const { activeStep, orientation } = useStepperContext()

  const status: "active" | "completed" | "pending" =
    completed || step < activeStep
      ? "completed"
      : step === activeStep
        ? "active"
        : "pending"

  return (
    <StepperItemContext.Provider value={{ step, status }}>
      <div
        data-slot="stepper-item"
        data-status={status}
        data-orientation={orientation}
        className={cn(
          "flex items-center",
          orientation === "horizontal" ? "flex-1 flex-row" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger
// ---------------------------------------------------------------------------

function StepperTrigger({
  className,
  children,
  ...props
}: React.ButtonHTMLAttributes<HTMLButtonElement>) {
  const { onStepClick } = useStepperContext()
  const { step, status } = useStepperItemContext()

  return (
    <button
      data-slot="stepper-trigger"
      data-status={status}
      type="button"
      role="tab"
      aria-selected={status === "active"}
      aria-current={status === "active" ? "step" : undefined}
      onClick={() => onStepClick(step)}
      className={cn(
        "inline-flex shrink-0 cursor-pointer items-center gap-2 rounded-md text-sm",
        "outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ---------------------------------------------------------------------------
// StepperIndicator
// ---------------------------------------------------------------------------

/**
 * A circular badge that displays the step number (or a custom icon).
 * When `children` is provided it replaces the automatic step number.
 */
function StepperIndicator({
  className,
  children,
  ...props
}: React.HTMLAttributes<HTMLSpanElement>) {
  const { step, status } = useStepperItemContext()

  return (
    <span
      data-slot="stepper-indicator"
      data-status={status}
      aria-hidden="true"
      className={cn(
        "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-xs font-semibold transition-colors",
        status === "completed" &&
          "border-primary bg-primary text-primary-foreground",
        status === "active" &&
          "border-primary bg-primary text-primary-foreground",
        status === "pending" &&
          "border-border bg-background text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? step}
    </span>
  )
}

// ---------------------------------------------------------------------------
// StepperTitle
// ---------------------------------------------------------------------------

function StepperTitle({
  className,
  ...props
}: React.HTMLAttributes<HTMLParagraphElement>) {
  const { status } = useStepperItemContext()

  return (
    <p
      data-slot="stepper-title"
      data-status={status}
      className={cn(
        "text-sm font-medium leading-none",
        status === "pending" ? "text-muted-foreground" : "text-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.HTMLAttributes<HTMLParagraphElement>) {
  const { status } = useStepperItemContext()

  return (
    <p
      data-slot="stepper-description"
      data-status={status}
      className={cn(
        "text-xs",
        status === "active" ? "text-foreground/70" : "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator
// ---------------------------------------------------------------------------

/**
 * A thin line drawn between two `<StepperItem>` elements.
 * Place it as the last child inside each `<StepperItem>` except the final one.
 *
 * - Horizontal orientation → renders a horizontal line (`h-px flex-1`).
 * - Vertical orientation   → renders a vertical line aligned under the indicator.
 */
