  const { status } = useStepperItemContext()

  return (
    <div
      data-slot="stepper-separator"
      data-status={status}
      data-orientation={orientation}
      role="none"
      className={cn(
        "shrink-0 bg-border transition-colors",
        orientation === "horizontal" ? "mx-2 h-px flex-1" : "my-1 ml-[15px] min-h-4 w-px",
        status === "completed" && "bg-primary",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperPanel
// ---------------------------------------------------------------------------

interface StepperPanelProps extends React.HTMLAttributes<HTMLDivElement> {
  /** The step this panel belongs to. Only rendered when its step is active. */
  step: number
}

/**
 * Content panel associated with a specific step.
 * Renders `null` when the panel's step is not the active step.
 * Can be placed anywhere inside `<Stepper>` — inside or outside `<StepperItem>`.
 */
function StepperPanel({ step, className, children, ...props }: StepperPanelProps) {
  const { activeStep } = useStepperContext()

