"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperDescription,
  StepperIndicator,
  StepperItem,
  StepperPanel,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const STEPS = [
  {
    step: 1,
    title: "Account",
    description: "Create your account",
    content:
      "Enter your email address and choose a secure password to get started.",
  },
  {
    step: 2,
    title: "Profile",
    description: "Set up your profile",
    content:
      "Add your name, avatar, and a short bio so others can learn about you.",
  },
  {
    step: 3,
    title: "Review",
    description: "Review and confirm",
    content:
      "Double-check your details and submit when you are ready to finish.",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)
  const total = STEPS.length

  return (
    <div className="flex w-full max-w-xl flex-col gap-6">
      {/* Horizontal stepper */}
      <Stepper step={activeStep} onStepChange={setActiveStep}>
        {STEPS.map(({ step, title, description }, index) => (
          <StepperItem key={step} step={step}>
            <StepperTrigger>
              <StepperIndicator>
                {step < activeStep ? (
                  <CheckIcon className="size-4" />
                ) : undefined}
              </StepperIndicator>
              <div className="hidden flex-col items-start sm:flex">
                <StepperTitle>{title}</StepperTitle>
                <StepperDescription>{description}</StepperDescription>
              </div>
            </StepperTrigger>
            {index < STEPS.length - 1 && <StepperSeparator />}
          </StepperItem>
        ))}
      </Stepper>

      {/* Step content panels */}
      {STEPS.map(({ step, title, content }) => (
        <StepperPanel
          key={step}
          step={step}
          className="rounded-lg border p-6"
        >
          <p className="mb-1 font-medium">{title}</p>
          <p className="text-sm text-muted-foreground">{content}</p>
        </StepperPanel>
      ))}

      {/* Navigation */}
      <div className="flex justify-between">
        <Button
          variant="outline"
          onClick={() => setActiveStep((s) => Math.max(1, s - 1))}
          disabled={activeStep === 1}
        >
          Previous
        </Button>
        <Button
          onClick={() => setActiveStep((s) => Math.min(total, s + 1))}
          disabled={activeStep === total}
        >
          {activeStep === total ? "Finish" : "Next"}
        </Button>
      </div>

      {/* Vertical stepper */}
      <p className="text-xs font-medium uppercase tracking-widest text-muted-foreground">
        Vertical orientation
      </p>
      <Stepper orientation="vertical">
        {STEPS.map(({ step, title, description }, index) => (
          <StepperItem key={step} step={step}>
            <StepperTrigger>
              <StepperIndicator>
                {step < activeStep ? (
                  <CheckIcon className="size-4" />
                ) : undefined}
              </StepperIndicator>
              <div className="flex flex-col items-start">
                <StepperTitle>{title}</StepperTitle>
                <StepperDescription>{description}</StepperDescription>
              </div>
            </StepperTrigger>
            {index < STEPS.length - 1 && <StepperSeparator />}
          </StepperItem>
        ))}
      </Stepper>
    </div>
  )
}

